const item = $input.first().json;

// Get original Telegram data - try multiple ways
let chatId, originalText;

try {
  const telegramData = $('Telegram Trigger').first().json;
  chatId = telegramData?.message?.chat?.id || telegramData?.chat?.id;
  originalText = telegramData?.message?.text || telegramData?.text;
} catch(e) {
  // Fallback: not available via reference
}

// If still no chatId, check if it was passed through
if (!chatId) {
  chatId = item?.message?.chat?.id || item?.chat?.id || '';
}
if (!originalText) {
  originalText = item?.message?.text || item?.text || '';
}

let text = '';

// Extract text from Gemini response
if (item?.content?.parts) {
  text = item.content.parts.map(p => p.text || '').join('');
} else if (item?.candidates) {
  text = item.candidates
    .map(c => c.content?.parts?.map(p => p.text || '').join('') || '')
    .join('');
} else if (item?.text) {
  text = item.text;
} else if (item?.output) {
  text = item.output;
} else {
  text = JSON.stringify(item);
}

// Clean up the text
text = text.replace(/```json/g, '').replace(/```/g, '').trim();

// Try to parse JSON
let parsed;
try {
  const temp = JSON.parse(text);
  if (Array.isArray(temp)) {
    parsed = typeof temp[0] === 'string' ? JSON.parse(temp[0]) : temp[0];
  } else {
    parsed = temp;
  }
} catch(e) {
  const jsonMatch = text.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch(e2) {
      return [{ json: { error: true, isTransaction: false, chatId, rawText: text } }];
    }
  } else {
    return [{ json: { error: true, isTransaction: false, chatId, rawText: text } }];
  }
}

if (!parsed || !parsed.is_transaction) {
  return [{ json: { error: false, isTransaction: false, chatId } }];
}

const ledgerEntry = `${parsed.date} ${parsed.payee}\n    ${parsed.expense_account}    ₹${parsed.amount.toFixed(2)}\n    ${parsed.source_account}`;

return [{
  json: {
    error: false,
    isTransaction: true,
    chatId: chatId,
    ledgerEntry: ledgerEntry,
    date: parsed.date,
    payee: parsed.payee,
    amount: parsed.amount,
    sourceAccount: parsed.source_account,
    expenseAccount: parsed.expense_account,
    originalSms: originalText
  }
}];

