const input = $input.first().json;
const data = input.callback_query?.data || '';
const chatId = input.callback_query?.message?.chat?.id || '';
const messageId = input.callback_query?.message?.message_id || '';

// Extract ledger entry from the bot's original message text
// The entry is between "Parsed Ledger Entry:" and "Amount:"
const originalMsg = input.callback_query?.message?.text || '';
let ledgerEntry = '';

const entryMatch = originalMsg.match(/Parsed Ledger Entry:\s*\n([\s\S]*?)\n\nAmount:/);
if (entryMatch) {
  ledgerEntry = entryMatch[1].trim();
}

let action = '';
if (data === 'approve') {
  action = 'approve';
} else if (data === 'edit') {
  action = 'edit';
} else if (data === 'reject') {
  action = 'reject';
}

return [{
  json: {
    action,
    ledgerEntry,
    chatId: String(chatId),
    messageId
  }
}];

