const input = $input.first().json;

if (input.message) {
  return [{ json: { ...input, routeType: 'message' } }];
} else if (input.callback_query) {
  return [{ json: { ...input, routeType: 'callback' } }];
}

return [{ json: { ...input, routeType: 'unknown' } }];
